}

scwin.f_subTitleExpression = function(sum_pchsSum,sum_sellTrans) {
    return sum_sellTrans == 0 ? 0 : Math.round( ( sum_pchsSum / sum_sellTrans ) * 100 * 10 ) / 10 ;
}
// Math.round( (SUM('pchsSum') / SUM('sellTrans')) * 100 * 10 ) / 10
